-- ESTUDIAR · Fase E-2 (FRANCÉS) — B1+B2 (unidades 13-24), SOLO DATOS.
-- La tabla study_theory y las RPCs de mig 178 son course-agnósticas por
-- construcción (derivan el curso de la unidad) → en/pt y fr A1+A2 intactos.
-- Los ejemplos traen la clave canónica `text` (idioma meta). NO toca motor FSRS,
-- economía, gating, certificación ni los otros idiomas. Prueba FORMATIVA.


-- ── Datos (idempotente por (course_id, unit_order)) ────────────────────────
insert into public.study_theory (course_id, unit_order, cefr_level, title, summary, sections, examples, pitfalls, quiz)
values ('20000000-0000-0000-0000-000000000003', 13, 'B1', 'Deseos y necesidad (subjonctif)', 'Aprende a formar el subjonctif présent y a usarlo tras il faut que, je veux que, bien que. Y, sobre todo, a NO usarlo donde el español sí lo pide.', '[{"heading": "Cómo se forma el subjonctif présent", "body": "Toma el radical de la tercera persona del plural del presente (ils) y añade -e, -es, -e, -ions, -iez, -ent. Ils parlent da que je parle; ils finissent da que je finisse. Casi nunca aparece sin que delante.", "bullets": ["ils parlent → que je parle, que tu parles, qu''il parle", "ils finissent → que nous finissions, que vous finissiez, qu''ils finissent", "nous y vous repiten la forma del imparfait: -ions, -iez", "en la lengua hablada, parle y parlent suenan igual"]}, {"heading": "Los siete irregulares que hay que saber", "body": "Siete verbos no siguen la regla del radical de ils y aparecen en casi todas las frases con que. Conviene memorizarlos como un bloque, porque son justo los más frecuentes del nivel B1.", "bullets": ["être → que je sois; avoir → que j''aie", "aller → que j''aille; faire → que je fasse", "pouvoir → que je puisse; savoir → que je sache", "vouloir → que tu veuilles (pero: que nous voulions)"]}, {"heading": "Cuándo se usa (y cuándo no)", "body": "Piden subjonctif il faut que, je veux que, je souhaite que, bien que, pour que y avant que. Pero si el sujeto no cambia, el francés prefiere el infinitivo: Je veux partir, nunca Je veux que je parte.", "bullets": ["Necesidad y voluntad: il faut que, je veux que, je souhaite que", "Conjunciones: bien que, pour que, avant que + subjonctif", "Mismo sujeto → infinitivo: Il faut partir; Je veux partir", "espérer que y penser que afirmativos llevan indicativo, no subjonctif"]}]'::jsonb, '[{"fr": "Il faut que tu viennes demain.", "es": "Hace falta que vengas mañana.", "text": "Il faut que tu viennes demain.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/study/a569f155-be4c-5373-878e-7a988c6b4b4c.mp3"}, {"fr": "Je veux partir tôt, mais je veux que tu restes.", "es": "Quiero irme temprano, pero quiero que te quedes.", "text": "Je veux partir tôt, mais je veux que tu restes.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/study/69f6b6eb-e45f-5840-98df-29c336240090.mp3"}, {"fr": "J''espère qu''il fera beau samedi.", "es": "Espero que haga buen tiempo el sábado.", "text": "J''espère qu''il fera beau samedi.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/study/7de03c95-2629-5d99-ae52-74fc65a24d82.mp3"}, {"fr": "Bien qu''elle soit fatiguée, elle sort avec nous.", "es": "Aunque esté cansada, sale con nosotros.", "text": "Bien qu''elle soit fatiguée, elle sort avec nous.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/study/f8073907-24a0-5d60-900c-ea9026148fa7.mp3"}]'::jsonb, '[{"title": "«Espero que venga» NO es «j''espère qu''il vienne»", "body": "Es el calco número uno del español. En francés espérer que va con INDICATIVO: J''espère qu''il vient, J''espère qu''il viendra. El que sí exige subjonctif es souhaiter que: Je souhaite qu''il vienne."}, {"title": "Con el mismo sujeto, infinitivo (no «que je»)", "body": "«Je veux que je parte» no existe en francés. Si quien quiere y quien actúa son la misma persona, se usa infinitivo: Je veux partir, Je souhaite réussir, Il faut travailler. El que + subjonctif solo entra cuando el segundo sujeto es otra persona."}, {"title": "penser / croire afirmativos van con indicativo", "body": "Je pense qu''il a raison, Je crois qu''elle peut venir. El subjonctif solo asoma cuando la frase es negativa o interrogativa: Je ne pense pas qu''il ait raison."}]'::jsonb, '[{"type": "multiple_choice", "prompt": "Mismo sujeto (yo quiero, yo me voy). ¿Cómo se dice «Quiero irme a Francia este verano»?", "options": ["Je veux partir en France cet été.", "Je veux que je parte en France cet été.", "Je veux que je pars en France cet été."], "answer": "Je veux partir en France cet été.", "id": "u13q1"}, {"type": "multiple_choice", "prompt": "Elige la forma correcta del subjonctif de ''être'' para ''tu'': «Il faut que tu ___ patient.»", "options": ["sois", "soit", "es"], "answer": "sois", "id": "u13q2"}, {"type": "multiple_choice", "prompt": "''Je crois que'' en afirmativo, ¿indicativo o subjonctif? «Je crois qu''elle ___ venir ce soir.»", "options": ["peut", "puisse", "pouvoir"], "answer": "peut", "id": "u13q3"}, {"type": "cloze", "prompt": "Completa con el subjonctif présent de ''faire'' (tu).", "text": "Il faut que tu ___ attention.", "answer": "fasses", "accepted": ["fasses"], "id": "u13q4"}, {"type": "cloze", "prompt": "Completa con el PRESENTE DE INDICATIVO de ''venir'' (il): recuerda que espérer que no lleva subjonctif.", "text": "J''espère qu''il ___ demain.", "answer": "vient", "accepted": ["vient", "viendra"], "id": "u13q5"}]'::jsonb)
