insert into public.study_theory (course_id, unit_order, cefr_level, title, summary, sections, examples, pitfalls, quiz)
values ('20000000-0000-0000-0000-000000000003', 14, 'B1', 'El futuro y el condicional', 'El conditionnel présent se forma con la base del futuro y las terminaciones del imperfecto. Sirve para hipótesis con «si + imparfait» y para pedir con cortesía.', '[{"heading": "Cómo se forma el conditionnel présent", "body": "Toma la MISMA base que el futur simple (el infinitivo, o la base irregular) y añade las terminaciones del imparfait: -ais, -ais, -ait, -ions, -iez, -aient. Los verbos irregulares en futuro lo son también en condicional, con la misma base.", "bullets": ["parler → je parlerais, nous parlerions, ils parleraient", "être → serais · avoir → aurais · aller → irais", "faire → ferais · pouvoir → pourrais · venir → viendrais", "Misma base que el futuro, terminaciones del imperfecto"]}, {"heading": "La hipótesis: si + imparfait, conditionnel", "body": "Para imaginar algo irreal o poco probable en el presente, el francés usa «si» + imparfait en la condición y conditionnel présent en el resultado. Es exactamente el español «si tuviera…, viajaría». Las dos partes pueden invertirse.", "bullets": ["Si j''avais le temps, je voyagerais plus", "Je t''aiderais si tu me le demandais", "Tras «si» de hipótesis nunca va conditionnel.", "«Au cas où» pide conditionnel: au cas où il pleuvrait"]}, {"heading": "El condicional de cortesía", "body": "En una tienda, un restaurante o una oficina, el presente suena brusco. El conditionnel suaviza la petición y es la forma normal y educada de pedir en francés.", "bullets": ["Je voudrais un café, s''il vous plaît", "Pourriez-vous m''aider ? / Auriez-vous une minute ?", "Tu devrais te reposer (consejo suave)", "«Je veux» suena exigente; «je voudrais», educado"]}]'::jsonb, '[{"fr": "Si j''avais le temps, je voyagerais plus.", "es": "Si tuviera tiempo, viajaría más.", "text": "Si j''avais le temps, je voyagerais plus.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/study/be41bdf8-f037-5b0a-bcfe-d7703dd35d5b.mp3"}, {"fr": "Je voudrais un café, s''il vous plaît.", "es": "Quisiera un café, por favor.", "text": "Je voudrais un café, s''il vous plaît.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/study/c9da3efd-7da3-5090-9d8f-85b9b5f9a2ed.mp3"}, {"fr": "Pourriez-vous répéter, s''il vous plaît ?", "es": "¿Podría repetir, por favor?", "text": "Pourriez-vous répéter, s''il vous plaît ?", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/study/a92ba651-1a65-5367-b726-8d423a1f3083.mp3"}, {"fr": "Prends un parapluie au cas où il pleuvrait.", "es": "Lleva un paraguas por si lloviera.", "text": "Prends un parapluie au cas où il pleuvrait.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/study/7d24b773-9c60-5fb2-8451-88d78e994090.mp3"}]'::jsonb, '[{"title": "«Si j''aurais» no existe", "body": "Después del «si» de hipótesis el francés jamás pone conditionnel: se dice «Si j''avais le temps», no «Si j''aurais le temps». Piensa en el español «si tuviera», nunca «si habría». El conditionnel va en la OTRA parte de la frase."}, {"title": "parlerai (futuro) vs parlerais (condicional)", "body": "Se pronuncian casi igual, pero se escriben distinto: «Demain je parlerai au directeur» (futuro real) frente a «Si je pouvais, je parlerais au directeur» (hipótesis). Fíjate en el contexto: si hay «si + imparfait», la terminación lleva -s."}, {"title": "«Au cas où» no lleva subjonctif", "body": "Aunque en español digamos «por si acaso llueva», el francés exige conditionnel: «au cas où il pleuvrait», «au cas où tu aurais besoin de moi». Nunca «au cas où il pleuve»."}]'::jsonb, '[{"type": "multiple_choice", "prompt": "Elige la forma correcta: «___ le temps, je voyagerais plus.»", "options": ["Si j''avais", "Si j''aurais", "Si j''aurai"], "answer": "Si j''avais", "id": "u14q1"}, {"type": "multiple_choice", "prompt": "Hipótesis, no futuro: «Si je pouvais, je lui ___ de la vérité.» Elige la forma del conditionnel.", "options": ["parlerais", "parlerai", "parlerait"], "answer": "parlerais", "id": "u14q2"}, {"type": "cloze", "prompt": "Cortesía en un café: escribe el verbe «vouloir» en conditionnel présent, 1ª persona (je).", "text": "Je ___ un café, s''il vous plaît.", "answer": "voudrais", "accepted": ["voudrais"], "id": "u14q3"}, {"type": "multiple_choice", "prompt": "Pide algo con cortesía: «___-vous m’aider, s’il vous plaît ?»", "options": ["Pourriez", "Pourrez", "Pouviez"], "answer": "Pourriez", "id": "u14q4"}, {"type": "cloze", "prompt": "Hipótesis: escribe «avoir» en imparfait con «je» (recuerda: tras «si», nunca conditionnel).", "text": "Si j''___ plus d''argent, j''achèterais cette maison.", "answer": "avais", "accepted": ["avais"], "id": "u14q5"}]'::jsonb)
