insert into public.study_theory (course_id, unit_order, cefr_level, title, summary, sections, examples, pitfalls, quiz)
values ('20000000-0000-0000-0000-000000000003', 16, 'B1', 'Concordancia del participio', 'En francés el participio pasado a veces cambia de forma según el sujeto o el complemento. Aquí ves las tres reglas: con être, con avoir y con los verbos pronominales.', '[{"heading": "Con être: concuerda con el sujeto", "body": "Un grupo CERRADO de verbos (no todo verbo de movimiento) (aller, venir, partir, arriver, rester, naître, mourir...) usan être. El participio se comporta como un adjetivo: añade -e si el sujeto es femenino y -s si es plural.", "bullets": ["Il est parti. / Elle est partie.", "Ils sont venus. / Elles sont venues.", "En español no cambia nada: «ella ha salido».", "Con vous formal singular femenino: «vous êtes partie»."]}, {"heading": "Con avoir: solo si el COD va delante", "body": "Con avoir el participio normalmente no cambia. Pero si el complemento directo aparece ANTES del verbo (pronombre le/la/les, el relativo que, o quel/combien de), el participio concuerda con ese complemento.", "bullets": ["J''ai acheté les fleurs. → sin cambio.", "Les fleurs que j''ai achetées. → COD delante.", "Je les ai vues. (les = les filles)", "Nunca concuerda con «en» ni con un COI."]}, {"heading": "Pronominales: depende del pronombre", "body": "Con se laver, se lever, s''habiller... el participio concuerda con el sujeto cuando el pronombre reflexivo es el complemento directo. Si detrás hay otro complemento directo, el pronombre pasa a ser indirecto y no hay concordancia.", "bullets": ["Elle s''est levée. (se = COD)", "Elle s''est lavé les mains. (COD = les mains)", "Elles se sont parlé. (parler à = COI)", "Truco: ¿hay un COD detrás? Entonces no concuerda."]}]'::jsonb, '[{"fr": "Les photos que j''ai prises sont magnifiques.", "es": "Las fotos que saqué son magníficas.", "text": "Les photos que j''ai prises sont magnifiques.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/study/3cdcdb8a-94b4-5435-b189-9d5162fc8dc0.mp3"}, {"fr": "Ma sœur est arrivée hier soir avec ses amies.", "es": "Mi hermana llegó ayer por la noche con sus amigas.", "text": "Ma sœur est arrivée hier soir avec ses amies.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/study/e7328cdd-2fd9-5b45-aad0-c6d48797a2b3.mp3"}, {"fr": "Elle s''est levée tôt, puis elle s''est lavé les mains.", "es": "Ella se levantó temprano y después se lavó las manos.", "text": "Elle s''est levée tôt, puis elle s''est lavé les mains.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/study/c2c32b07-3800-506e-ae96-5ab55ab618d4.mp3"}, {"fr": "J''ai vu tes clés : je les ai mises sur la table.", "es": "Vi tus llaves: las puse sobre la mesa.", "text": "J''ai vu tes clés : je les ai mises sur la table.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/study/55c949a3-b138-5316-824b-f130f322af6e.mp3"}]'::jsonb, '[{"title": "Concordar con avoir cuando el COD va detrás", "body": "«J''ai achetées des fleurs» es incorrecto. Con avoir, si el complemento directo viene DESPUÉS del verbo, el participio no cambia nunca: «J''ai acheté des fleurs». La concordancia solo aparece si el COD está delante."}, {"title": "Olvidar la -e porque no se oye", "body": "«acheté» y «achetées» suenan igual, así que es fácil no escribirla. Pero con participios en -s o -t sí se oye la diferencia: pris/prise, mis/mise, fait/faite. Ahí un error se nota al hablar."}, {"title": "Concordar todos los pronominales", "body": "«Elle s''est lavée les mains» es incorrecto: el complemento directo es «les mains» y va detrás, así que el participio queda invariable: «Elle s''est lavé les mains». Compara con «Elle s''est lavée» (sin nada detrás), donde sí concuerda."}]'::jsonb, '[{"type": "multiple_choice", "prompt": "Marie habla de sí misma (femenino singular). ¿Cuál es la frase correcta?", "options": ["Je suis partie à huit heures.", "Je suis parti à huit heures.", "Je suis parties à huit heures."], "answer": "Je suis partie à huit heures.", "id": "u16q1"}, {"type": "multiple_choice", "prompt": "«Les fleurs» es femenino plural y va delante del verbo. ¿Cuál es la frase correcta?", "options": ["Les fleurs que j''ai achetées sont belles.", "Les fleurs que j''ai acheté sont belles.", "Les fleurs que j''ai achetés sont belles."], "answer": "Les fleurs que j''ai achetées sont belles.", "id": "u16q2"}, {"type": "multiple_choice", "prompt": "El complemento directo es «les mains» y va DESPUÉS del verbo. ¿Cuál es la frase correcta?", "options": ["Elle s''est lavé les mains.", "Elle s''est lavée les mains.", "Elle s''est lavées les mains."], "answer": "Elle s''est lavé les mains.", "id": "u16q3"}, {"type": "multiple_choice", "prompt": "Completa con el auxiliar correcto: «Mes sœurs ___ parties très tôt ce matin.»", "options": ["sont", "ont", "est"], "answer": "sont", "id": "u16q4"}, {"type": "cloze", "prompt": "Completa con el auxiliar correcto. «Acheter» no es un verbo de movimiento; el sujeto es «nous».", "text": "Nous ___ acheté deux billets pour le concert.", "answer": "avons", "accepted": ["avons"], "id": "u16q5"}]'::jsonb)
