  quiz = excluded.quiz, updated_at = now();
insert into public.study_theory (course_id, unit_order, cefr_level, title, summary, sections, examples, pitfalls, quiz)
values ('20000000-0000-0000-0000-000000000003', 17, 'B1', 'Estilo indirecto', 'Aprende a contar lo que otra persona dijo, preguntó o mandó. Verás el retroceso de tiempos, las preguntas indirectas y el imperativo con «de + infinitif».', '[{"heading": "1 · Contar lo que alguien dijo: el retroceso de tiempos", "body": "Con «dire que» en presente no cambia nada: «Il dit qu''il est fatigué». Si el verbo introductor va en pasado (a dit, disait), los tiempos suelen retroceder un paso hacia atrás.", "bullets": ["présent → imparfait: est → était", "futur → conditionnel: viendra → viendrait", "passé composé → plus-que-parfait: a mangé → avait mangé", "Si sigue vigente, puedes NO retroceder"]}, {"heading": "2 · Preguntas indirectas: sin inversión y sin «?»", "body": "La pregunta incrustada usa orden de afirmación: sujeto antes del verbo, sin inversión y sin signo de interrogación. La palabra interrogativa (où, quand, pourquoi, comment) se mantiene.", "bullets": ["«Où habites-tu ?» → «Il demande où j''habite.»", "Pregunta de sí/no → «si»: «Il demande si je viens.»", "«qu''est-ce que» → «ce que»", "«qu''est-ce qui» → «ce qui»"]}, {"heading": "3 · Órdenes: «de + infinitif»", "body": "El imperativo referido no usa «que». Tras dire, demander o conseiller se pone «de» más infinitivo. En negativo, «ne pas» va delante del infinitivo entero.", "bullets": ["«Pars !» → «Il m''a dit de partir.»", "«Attendez.» → «Elle nous a demandé d''attendre.»", "Negativo: «Il m''a dit de ne pas partir.»", "La orden referida va con «de» + infinitivo, no con «que»."]}]'::jsonb, '[{"fr": "Il m''a dit qu''il était fatigué.", "es": "Me dijo que estaba cansado.", "text": "Il m''a dit qu''il était fatigué.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/study/2e427668-7748-58b9-bcdf-d1901b78844b.mp3"}, {"fr": "Elle demande si tu viens ce soir.", "es": "Ella pregunta si vienes esta noche.", "text": "Elle demande si tu viens ce soir.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/study/6a7dd95d-4863-5daf-a84e-1f180afa011e.mp3"}, {"fr": "Je ne sais pas ce que tu veux.", "es": "No sé qué quieres.", "text": "Je ne sais pas ce que tu veux.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/study/e47eaada-cd7e-5850-8108-2acf9c96a3d8.mp3"}, {"fr": "Le professeur nous a dit de ne pas parler.", "es": "El profesor nos dijo que no habláramos.", "text": "Le professeur nous a dit de ne pas parler.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/study/648a2db7-fd4a-514f-ba96-5ca7ad87665c.mp3"}]'::jsonb, '[{"title": "«qu''est-ce que» no sobrevive dentro de la frase", "body": "En pregunta directa dices «Qu''est-ce que tu veux ?», pero al contarla se transforma: «Il demande ce que tu veux.» Nunca «Il demande qu''est-ce que tu veux». Si el interrogativo es sujeto («Qu''est-ce qui se passe ?»), se convierte en «ce qui»: «Il demande ce qui se passe.»"}, {"title": "El retroceso NO siempre es obligatorio", "body": "Si lo dicho sigue siendo verdad hoy, el francés moderno acepta las dos formas: «Il a dit qu''il habite à Lyon» y «Il a dit qu''il habitait à Lyon» son ambas correctas. El retroceso es la opción de manual y la más segura en examen, no una ley absoluta."}, {"title": "Tras «dire», la orden pide «de», no «que»", "body": "El español dice «Me dijo que saliera» y el hispanohablante calca «Il m''a dit qu''il sorte» ✗. En francés la orden referida es «Il m''a dit de sortir». Reserva «que» para contar información («Il m''a dit qu''il sortait» = me dijo que salía)."}]'::jsonb, '[{"type": "multiple_choice", "prompt": "Pon en estilo indirecto: «Qu''est-ce que tu fais ?» → Il demande ___", "options": ["ce que tu fais", "qu''est-ce que tu fais", "ce qui tu fais"], "answer": "ce que tu fais", "id": "u17q1"}, {"type": "multiple_choice", "prompt": "Pon en estilo indirecto: «Qu''est-ce qui ne va pas ?» → Elle demande ___", "options": ["ce qui ne va pas", "ce que ne va pas", "qu''est-ce qui ne va pas"], "answer": "ce qui ne va pas", "id": "u17q2"}, {"type": "multiple_choice", "prompt": "«Ferme la porte !» → Il m''a dit ___ la porte.", "options": ["de fermer", "que fermer", "que je ferme"], "answer": "de fermer", "id": "u17q3"}, {"type": "cloze", "prompt": "Pregunta de sí/no en estilo indirecto. Completa con la conjunción que introduce la pregunta.", "text": "«Tu viens ?» → Il demande ___ je viens.", "answer": "si", "accepted": ["si"], "id": "u17q4"}, {"type": "cloze", "prompt": "Aplica el retroceso de tiempos: présent → imparfait. Escribe la forma de «être» que corresponde.", "text": "«Je suis malade.» → Il a dit qu''il ___ malade.", "answer": "était", "accepted": ["était", "etait"], "id": "u17q5"}]'::jsonb)
