insert into public.study_theory (course_id, unit_order, cefr_level, title, summary, sections, examples, pitfalls, quiz)
values ('20000000-0000-0000-0000-000000000003', 18, 'B1', 'Pronombres (le, lui, y, en)', 'Aprende a no repetir el complemento: le/la/les y lui/leur para personas y cosas, y los dos pronombres que el español no tiene, y y en. También dónde se colocan.', '[{"heading": "le, la, les (directo) · lui, leur (indirecto)", "body": "Si el verbo lleva el complemento SIN preposición, usa le, la, les: «Je regarde le film» → «Je le regarde». Si el verbo lleva «à + persona», usa lui (una) o leur (varias): «Je parle à Marie» → «Je lui parle».", "bullets": ["le/la/les sustituyen a un complemento sin preposición.", "lui = a él o a ella; leur = a ellos.", "leur pronombre nunca lleva -s: «Je leur parle»."]}, {"heading": "y y en: los que el español calla", "body": "y sustituye «à + cosa» o un lugar: «Je pense à mon travail» → «J''y pense». en sustituye «de + cosa» y las cantidades: «Je viens de Paris» → «J''en viens»; «J''ai deux frères» → «J''en ai deux».", "bullets": ["y reemplaza à + cosa o lugar, nunca una persona.", "en reemplaza de + cosa o lugar y toda cantidad.", "Con número o beaucoup, en es obligatorio en francés."]}, {"heading": "Dónde se coloca el pronombre", "body": "Va DELANTE del verbo conjugado: «Je le vois». Con dos verbos, va delante del INFINITIVO: «Je vais le faire», «Tu peux y aller». En negación: «Je ne le vois pas».", "bullets": ["Con dos verbos, el pronombre precede al infinitivo.", "Excepción: en imperativo afirmativo va detrás, «Regarde-le !».", "Pero en imperativo negativo vuelve delante: «Ne le regarde pas !»."]}]'::jsonb, '[{"fr": "Je lui téléphone tous les soirs.", "es": "Lo llamo por teléfono todas las noches.", "text": "Je lui téléphone tous les soirs.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/study/82e8408e-9bba-55a1-b3cf-93b6f8f3a728.mp3"}, {"fr": "J''y pense souvent.", "es": "Pienso en ello a menudo.", "text": "J''y pense souvent.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/study/8a738e1e-d316-52ca-8c76-77cb109f6eef.mp3"}, {"fr": "Des amis ? J''en ai beaucoup.", "es": "¿Amigos? Tengo muchos.", "text": "Des amis ? J''en ai beaucoup.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/study/a25744fd-4936-5baf-9777-d41435513a68.mp3"}, {"fr": "Je vais le faire demain.", "es": "Voy a hacerlo mañana.", "text": "Je vais le faire demain.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/study/bd824d1a-3974-548d-9ff9-454f8e2c28c6.mp3"}]'::jsonb, '[{"title": "En español no dices «de ello»; en francés SÍ", "body": "«¿Tienes hermanos? Tengo dos» es «J''en ai deux», no «J''ai deux». Con una cantidad sola, el francés exige en. Lo mismo con «J''en veux» (Quiero)."}, {"title": "El pronombre no va detrás del infinitivo", "body": "En español dices «voy a hacerlo»; en francés el pronombre va DELANTE del infinitivo: «Je vais le faire», no «Je vais faire le». Solo el imperativo afirmativo lo pone detrás: «Fais-le !»."}, {"title": "penser à → y, pero penser de → en", "body": "La preposición del verbo manda. «Je pense à mes vacances» → «J''y pense». «Qu''est-ce que tu penses de ce film ?» → «J''en pense du bien». No elijas por el significado, sino por la preposición."}]'::jsonb, '[{"type": "multiple_choice", "prompt": "Elige el pronombre correcto: «Tu vois mes clés ? — Oui, je ___ vois.»", "options": ["les", "le", "leur"], "answer": "les", "id": "u18q1"}, {"type": "multiple_choice", "prompt": "«Je téléphone à mes parents» → «Je ___ téléphone.» Elige el pronombre.", "options": ["leur", "lui", "les"], "answer": "leur", "id": "u18q2"}, {"type": "cloze", "prompt": "Sustituye «à mon voyage» por el pronombre adecuado (una palabra).", "text": "Je pense à mon voyage. → J''___ pense souvent.", "answer": "y", "accepted": ["y"], "id": "u18q3"}, {"type": "cloze", "prompt": "Completa con el pronombre de cantidad que falta (una palabra).", "text": "Tu as des frères ? — Oui, j''___ ai deux.", "answer": "en", "accepted": ["en"], "id": "u18q4"}, {"type": "cloze", "prompt": "Escribe el pronombre y el infinitivo en el orden correcto (dos palabras).", "text": "Tu vas regarder ce film ? — Oui, je vais ___ ce soir.", "answer": "le regarder", "accepted": ["le regarder"], "id": "u18q5"}]'::jsonb)
