insert into public.study_theory (course_id, unit_order, cefr_level, title, summary, sections, examples, pitfalls, quiz)
values ('20000000-0000-0000-0000-000000000003', 19, 'B2', 'El subjuntivo pasado (subjonctif passé)', 'El subjonctif passé se forma con avoir o être en subjuntivo más el participio, y dice que esa acción ya ocurrió antes que la principal.', '[{"heading": "Cómo se forma", "body": "Se forma con el subjonctif présent de avoir o de être más el participio pasado. El auxiliar es el mismo que en el passé composé: «que j''aie parlé», «que je sois parti». El español, en cambio, usa siempre «haber».", "bullets": ["avoir: que j''aie, que tu aies, qu''il ait, qu''ils aient.", "être: que je sois, que tu sois, qu''il soit, qu''ils soient.", "El francés elige el auxiliar; el español no lo hace."]}, {"heading": "Anterioridad: passé o présent", "body": "El subjonctif passé indica que su acción ocurrió ANTES que la de la principal. El présent expresa lo simultáneo o lo posterior. Compara: «Je suis content qu''elle vienne» (vendrá) frente a «Je suis content qu''elle soit venue» (ya vino).", "bullets": ["Anterior → passé; simultáneo o futuro → présent.", "«Bien qu''il ait fini» significa que ya terminó.", "Con être, el participio concuerda: «qu''elle soit venue»."]}, {"heading": "Avant que y après que", "body": "Tras «avant que» el francés usa subjonctif présent, aunque la acción sea futura. Tras «après que» la norma pide INDICATIVO, porque el hecho ya es real; el calco del español («después de que venga») mete ahí un subjuntivo indebido.", "bullets": ["avant que + subjonctif présent, aunque hables del futuro.", "après que + indicatif: «après qu''il est arrivé».", "En el oral se oye subjonctif tras «après que»; en examen, indicativo."]}]'::jsonb, '[{"fr": "Je suis content que tu sois venu.", "es": "Me alegra que hayas venido.", "text": "Je suis content que tu sois venu.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/study/0e1ca5f1-b912-53e9-ba29-30294c578f2e.mp3"}, {"fr": "Bien qu''il ait beaucoup travaillé, il a échoué à l''examen.", "es": "Aunque trabajó mucho, suspendió el examen.", "text": "Bien qu''il ait beaucoup travaillé, il a échoué à l''examen.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/study/536c176f-3537-52d0-b21a-37b87338d308.mp3"}, {"fr": "Partons avant qu''il pleuve.", "es": "Vámonos antes de que llueva.", "text": "Partons avant qu''il pleuve.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/study/adf8168b-2af0-5211-a2af-a296046aa8d2.mp3"}, {"fr": "Après qu''elle est partie, nous avons rangé la salle.", "es": "Después de que se fue, ordenamos la sala.", "text": "Après qu''elle est partie, nous avons rangé la salle.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/study/ddbf39fb-d23d-5624-855c-d4bf6c5793c5.mp3"}]'::jsonb, '[{"title": "«Après que» no lleva subjuntivo", "body": "El español dice «después de que haya llegado» y el hispanohablante calca «après qu''il soit arrivé». La norma francesa pide indicativo: «après qu''il est arrivé». Es la trampa más fina de este tema en un examen escrito."}, {"title": "El auxiliar no siempre es avoir", "body": "En español todo va con «haber», pero el francés elige avoir o être igual que en el passé composé. Con verbos de movimiento y pronominales: «qu''il soit allé», «qu''elle se soit levée», nunca «qu''il ait allé»."}, {"title": "«Avant que» no pide subjonctif passé", "body": "Aunque hables de algo futuro, tras «avant que» se usa el subjonctif présent: «avant qu''il parte». Poner ahí el passé («avant qu''il soit parti») invierte el orden temporal que quieres expresar."}]'::jsonb, '[{"type": "multiple_choice", "prompt": "Ella terminó el informe ayer y hoy tú te alegras. ¿Qué frase marca que la acción del subjuntivo es ANTERIOR?", "options": ["Je suis content qu''elle ait terminé le rapport.", "Je suis content qu''elle termine le rapport.", "Je suis content qu''elle terminera le rapport."], "answer": "Je suis content qu''elle ait terminé le rapport.", "id": "u19q1"}, {"type": "multiple_choice", "prompt": "Según la norma escrita (registro de examen), ¿cuál es correcta tras «après que»?", "options": ["Après qu''il est arrivé, nous avons commencé la réunion.", "Après qu''il soit arrivé, nous avons commencé la réunion.", "Après qu''il ait arrivé, nous avons commencé la réunion."], "answer": "Après qu''il est arrivé, nous avons commencé la réunion.", "id": "u19q2"}, {"type": "cloze", "prompt": "Escribe el auxiliar en subjuntivo que corresponde al verbo «partir».", "text": "Je regrette qu''elle ___ partie sans nous dire au revoir.", "answer": "soit", "accepted": ["soit"], "id": "u19q3"}, {"type": "cloze", "prompt": "Escribe el auxiliar en subjuntivo para formar el subjonctif passé de «travailler».", "text": "Bien qu''il ___ beaucoup travaillé, il a échoué à l''examen.", "answer": "ait", "accepted": ["ait"], "id": "u19q4"}, {"type": "multiple_choice", "prompt": "¿Cuál está bien escrita? Fíjate en el auxiliar y en la concordancia del participio.", "options": ["Je suis désolé qu''elles soient parties sans nous.", "Je suis désolé qu''elles soient parti sans nous.", "Je suis désolé qu''elles aient parties sans nous."], "answer": "Je suis désolé qu''elles soient parties sans nous.", "id": "u19q5"}]'::jsonb)
