insert into public.study_theory (course_id, unit_order, cefr_level, title, summary, sections, examples, pitfalls, quiz)
values ('20000000-0000-0000-0000-000000000003', 20, 'B2', 'Concordancia de tiempos y lo irreal del pasado', 'Aprende a construir el conditionnel passé y a encadenar los tres tipos de «si» sin caer en el error clásico. Verás también el arrepentimiento y la noticia no confirmada.', '[{"heading": "El conditionnel passé: avoir/être en conditionnel + participio", "body": "Se forma con el conditionnel présent de avoir o être más el participio pasado: «j''aurais fait», «je serais venu». Elige el auxiliar igual que en el passé composé: los verbos de movimiento y los pronominales van con être, y entonces el participio concuerda con el sujeto.", "bullets": ["j''aurais, tu aurais, il aurait, nous aurions, vous auriez, ils auraient", "je serais, tu serais, elle serait, nous serions, ils seraient", "Con être: «elle serait partie», «nous nous serions levés»", "Con avoir no hay concordancia con el sujeto"]}, {"heading": "Los tres «si»: una sola tabla mental", "body": "La condición manda el tiempo del resultado. Real: si + présent → futur. Improbable: si + imparfait → conditionnel présent. Imposible, ya pasado: si + plus-que-parfait → conditionnel passé. La frase con «si» de condición nunca lleva futur ni conditionnel.", "bullets": ["Si tu viens, je serai content. (real)", "Si tu venais, je serais content. (improbable)", "Si tu étais venu, j''aurais été content. (imposible)", "Mezcla posible: «Si j''avais étudié, je serais médecin aujourd''hui»"]}, {"heading": "Otros dos usos: arrepentimiento y noticia no confirmada", "body": "El conditionnel passé expresa lo que no hiciste y lamentas: «j''aurais dû partir plus tôt» equivale a «debería haberme ido antes». En la prensa marca información sin confirmar: «Le président aurait démissionné» significa «habría dimitido», según se dice.", "bullets": ["j''aurais dû = debería haber; j''aurais pu = habría podido", "tu aurais voulu, on aurait aimé: deseos que no se cumplieron", "Prensa: «Il y aurait eu vingt blessés»"]}]'::jsonb, '[{"fr": "Si j''avais su, je serais venu plus tôt.", "es": "Si hubiera sabido, habría venido antes.", "text": "Si j''avais su, je serais venu plus tôt.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/study/11141d5d-fb27-5c0f-be1e-037a88c3dbed.mp3"}, {"fr": "Tu aurais dû me téléphoner hier soir.", "es": "Deberías haberme llamado ayer por la noche.", "text": "Tu aurais dû me téléphoner hier soir.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/study/ff775c9c-e0e1-55a2-b2a7-ce31428db264.mp3"}, {"fr": "Si elle avait accepté ce poste, elle vivrait à Lyon aujourd''hui.", "es": "Si hubiera aceptado ese puesto, viviría en Lyon hoy.", "text": "Si elle avait accepté ce poste, elle vivrait à Lyon aujourd''hui.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/study/eec6de98-afd2-5f27-b1b0-1e5ca9a30c35.mp3"}, {"fr": "Selon la presse, le ministre aurait quitté le gouvernement.", "es": "Según la prensa, el ministro habría dejado el gobierno.", "text": "Selon la presse, le ministre aurait quitté le gouvernement.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/study/9231e3bf-5ed8-51e9-967a-2dde6bafb687.mp3"}]'::jsonb, '[{"title": "«Si j''aurais su» no existe", "body": "Detrás de «si» condicional jamás se pone conditionnel. El español «si hubiera sabido» se traduce con plus-que-parfait: «si j''avais su». El conditionnel passé va en la otra mitad: «je serais venu»."}, {"title": "El auxiliar decide la concordancia", "body": "Con être el participio concuerda con el sujeto: «elle serait partie», «ils seraient rentrés». Con avoir no: «elle aurait fini» se escribe igual para él y para ella."}, {"title": "«J''aurais dû» no es «je devrais»", "body": "«Je devrais partir» habla del presente o del futuro: debería irme. «J''aurais dû partir» mira al pasado: debería haberme ido, y ya no puedo cambiarlo."}]'::jsonb, '[{"type": "multiple_choice", "prompt": "Elige la forma correcta: «___ su, je serais venu plus tôt.»", "options": ["Si j''avais", "Si j''aurais", "Si j''aurai"], "answer": "Si j''avais", "id": "u20q1"}, {"type": "multiple_choice", "prompt": "Hipótesis improbable sobre el presente: «Si j''avais plus de temps, je ___ un cours de piano.»", "options": ["prendrais", "prendrai", "aurais pris"], "answer": "prendrais", "id": "u20q2"}, {"type": "multiple_choice", "prompt": "¿Qué frase expresa una noticia NO confirmada?", "options": ["Le directeur aurait démissionné hier.", "Le directeur a démissionné hier.", "Le directeur démissionnera demain."], "answer": "Le directeur aurait démissionné hier.", "id": "u20q3"}, {"type": "cloze", "prompt": "Completa con el AUXILIAR del plus-que-parfait de «savoir» (una palabra).", "text": "Si j''___ su, je ne serais pas venu.", "answer": "avais", "accepted": ["avais"], "id": "u20q4"}, {"type": "multiple_choice", "prompt": "Atención a la concordancia con «elle»: «Si elle avait eu la clé, ___ avant nous.»", "options": ["elle serait partie", "elle serait parti", "elle serait partis"], "answer": "elle serait partie", "id": "u20q5"}]'::jsonb)
