  quiz = excluded.quiz, updated_at = now();
insert into public.study_theory (course_id, unit_order, cefr_level, title, summary, sections, examples, pitfalls, quiz)
values ('20000000-0000-0000-0000-000000000003', 21, 'B2', 'El discurso indirecto en pasado', 'Cuando el verbo introductor va en pasado (il a dit, elle a expliqué), los tiempos retroceden y los marcadores de tiempo y lugar también cambian.', '[{"heading": "El retroceso de los tiempos", "body": "Con un introductor en pasado (il a dit que, elle a répondu que), el verbo de lo dicho retrocede un escalón. El imparfait y el plus-que-parfait ya no cambian: son el final de la cadena.", "bullets": ["présent → imparfait : « je pars » → qu''il partait", "passé composé → plus-que-parfait : qu''il était parti", "futur simple → conditionnel présent : qu''il partirait", "futur antérieur → conditionnel passé : qu''il serait parti"]}, {"heading": "El imperativo y las preguntas indirectas", "body": "El imperativo se vuelve « de + infinitivo ». En las preguntas indirectas no hay inversión ni signo de interrogación: el sujeto va delante del verbo, como en una frase normal.", "bullets": ["« Pars ! » → Il m''a dit de partir.", "Est-ce que… → s''il / si elle (sin inversión)", "Qu''est-ce que… → ce que ; Qu''est-ce qui… → ce qui"]}, {"heading": "Los marcadores de tiempo y lugar", "body": "Es el punto que más olvidan los hispanohablantes: al pasar al pasado, las palabras que señalan el momento y el sitio también se desplazan, porque ya no hablamos desde el día en que se dijo.", "bullets": ["aujourd''hui → ce jour-là ; hier → la veille", "demain → le lendemain ; ici → là", "la semaine prochaine → la semaine suivante"]}]'::jsonb, '[{"fr": "Il a dit qu''il partirait le lendemain.", "es": "Dijo que se iría al día siguiente.", "text": "Il a dit qu''il partirait le lendemain.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/study/276e6950-2f7d-50b2-a2d5-be93865f1eff.mp3"}, {"fr": "Elle a expliqué qu''elle avait déjà envoyé le dossier la veille.", "es": "Explicó que ya había enviado el expediente el día anterior.", "text": "Elle a expliqué qu''elle avait déjà envoyé le dossier la veille.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/study/7b369a60-88f7-57fe-b131-2b15b85f0005.mp3"}, {"fr": "Le médecin m''a demandé ce que je ressentais et si je dormais bien.", "es": "El médico me preguntó qué sentía y si dormía bien.", "text": "Le médecin m''a demandé ce que je ressentais et si je dormais bien.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/study/21ed97c1-7eb9-510c-b68d-ec7e165ec5dd.mp3"}, {"fr": "Mon chef m''a dit de ne pas répondre à ce message.", "es": "Mi jefe me dijo que no respondiera a ese mensaje.", "text": "Mon chef m''a dit de ne pas répondre à ce message.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/study/128bfbd5-ffd6-5ecf-9f85-c6d01a4baec8.mp3"}]'::jsonb, '[{"title": "«demain» que se queda sin moverse", "body": "El error más frecuente del hispanohablante: « Il a dit qu''il viendrait demain. » Si cuentas después lo que se dijo entonces, el francés exige « le lendemain ». « Demain » solo sirve si hablas del mañana de hoy mismo."}, {"title": "Confundir «partirait» con el futuro", "body": "Futur y conditionnel se parecen mucho al oído (je partirai / je partirais), pero tras un introductor en pasado solo cabe el conditionnel: « Il a dit qu''il partirait. » El futur solo se mantiene si el hecho sigue por venir al contarlo."}, {"title": "Poner una pregunta directa dentro de la frase", "body": "Nada de inversión ni de « qu''est-ce que » en la indirecta: no « Il m''a demandé qu''est-ce que je faisais », sino « Il m''a demandé ce que je faisais ». Y sin signo de interrogación."}]'::jsonb, '[{"type": "multiple_choice", "prompt": "Pasa al discurso indirecto: Il a dit : « Je partirai à midi. » → Il a dit qu''il ___ à midi.", "options": ["partirait", "partira", "partait"], "answer": "partirait", "id": "u21q1"}, {"type": "multiple_choice", "prompt": "Lundi, Marc a dit : « Je viens demain. » Hoy es miércoles y lo cuentas. → Marc a dit qu''il venait ___.", "options": ["le lendemain", "demain", "aujourd''hui"], "answer": "le lendemain", "id": "u21q2"}, {"type": "cloze", "prompt": "Completa con el equivalente indirecto de « hier ». Elle a raconté qu''elle avait vu ce film ___ (= el día anterior).", "text": "Elle a raconté qu''elle avait vu ce film ___.", "answer": "la veille", "accepted": ["la veille"], "id": "u21q3"}, {"type": "multiple_choice", "prompt": "«Qu''est-ce que tu veux ?» en estilo indirecto: «Il m''a demandé ___ je voulais.»", "options": ["ce que", "ce qui", "qu''est-ce que"], "answer": "ce que", "id": "u21q4"}, {"type": "cloze", "prompt": "El imperativo «Attends-moi !» en estilo indirecto. Escribe la preposición (una palabra).", "text": "Il m''a dit ___ l''attendre.", "answer": "de", "accepted": ["de", "d''"], "id": "u21q5"}]'::jsonb)
