insert into public.study_theory (course_id, unit_order, cefr_level, title, summary, sections, examples, pitfalls, quiz)
values ('20000000-0000-0000-0000-000000000003', 22, 'B2', 'Participio presente, gerundio y adjetivo verbal', 'Las tres formas francesas en -ant: el participe présent (invariable), el gérondif (en + -ant) y el adjectif verbal (concuerda). Y por qué el gerundio español no se traduce casi nunca por -ant.', '[{"heading": "Le participe présent : invariable", "body": "Radical de la forma «nous» del presente + -ant: nous finissons → finissant. Irregulares: ayant (avoir), étant (être), sachant (savoir). Es INVARIABLE y expresa causa o acción simultánea, sobre todo en lengua escrita o formal.", "bullets": ["Causa: «Ne sachant pas la réponse, il s''est tu».", "Nunca concuerda: «des enfants criant dans la rue».", "Suele llevar complemento o negación detrás."]}, {"heading": "Le gérondif : en + -ant", "body": "Se forma con «en» + participe présent e indica simultaneidad o manera. En el uso corriente el sujeto es el mismo que el del verbo principal: «Il travaille en écoutant de la musique». «Tout en» añade oposición o insistencia.", "bullets": ["Simultaneidad: «Elle chante en cuisinant».", "Manera o medio: «On apprend en pratiquant».", "Mismo sujeto en el uso corriente; hay refranes fijos que no lo siguen."]}, {"heading": "L''adjectif verbal : concuerda y cambia", "body": "Cuando la forma en -ant funciona como adjetivo, concuerda en género y número: «une histoire fatigante», «des images choquantes». Varios cambian de grafía respecto al participio: fatigant/fatiguant, provocant/provoquant, différent/différant.", "bullets": ["Adjetivo: concuerda («des couleurs voyantes»).", "Participe présent: invariable, con complemento detrás.", "Ojo con la grafía: -gant/-guant, -cant/-quant, -ent/-ant."]}]'::jsonb, '[{"fr": "Il travaille en écoutant de la musique.", "es": "Trabaja escuchando música.", "text": "Il travaille en écoutant de la musique.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/study/d3203fa9-24bc-5da2-93d5-2f9921de5f37.mp3"}, {"fr": "Ne sachant pas la réponse, il s''est tu.", "es": "Como no sabía la respuesta, se calló.", "text": "Ne sachant pas la réponse, il s''est tu.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/study/fc7b6958-5d67-5cb0-b6be-6f74b5eed25e.mp3"}, {"fr": "C''était une réunion fatigante, mais très utile.", "es": "Fue una reunión agotadora, pero muy útil.", "text": "C''était une réunion fatigante, mais très utile.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/study/7bfcd74a-341f-50ef-bab4-c0c9e3162657.mp3"}, {"fr": "En ce moment, je mange ; je ne peux pas te parler.", "es": "Ahora mismo estoy comiendo; no puedo hablarte.", "text": "En ce moment, je mange ; je ne peux pas te parler.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/study/d0766bd5-edb5-521c-a48a-207bb580df37.mp3"}]'::jsonb, '[{"title": "«Estoy comiendo» no es «je suis mangeant»", "body": "El francés no forma el progresivo con -ant. Se dice «je mange» y, si quieres insistir en la acción en curso, «je suis en train de manger». «Je suis mangeant» no existe: es el calco más grave del español."}, {"title": "El gérondif quiere el mismo sujeto", "body": "«Il travaille en écoutant» significa que él trabaja y él escucha. Si los sujetos son distintos, usa «pendant que» o «tandis que»: «Il travaille pendant que sa sœur écoute de la musique»."}, {"title": "¿Concuerda o no concuerda?", "body": "Si describe, es adjetivo y concuerda: «une réunion fatigante». Si expresa una acción con complemento, es participe présent y queda invariable: «une réunion fatiguant tout le monde»."}]'::jsonb, '[{"type": "multiple_choice", "prompt": "«Ce travail est très ___.» ¿Qué forma corresponde al ADJETIVO VERBAL (describe el trabajo)?", "options": ["fatigant", "fatiguant", "en fatiguant"], "answer": "fatigant", "id": "u22q1"}, {"type": "multiple_choice", "prompt": "¿Cómo se dice de forma natural «Ahora mismo estoy comiendo»?", "options": ["En ce moment, je mange.", "En ce moment, je suis mangeant.", "En ce moment, je suis en mangeant."], "answer": "En ce moment, je mange.", "id": "u22q2"}, {"type": "multiple_choice", "prompt": "«Ce sont des images ___ (choquer).» Elige la forma correcta del adjetivo verbal.", "options": ["choquantes", "choquant", "en choquant"], "answer": "choquantes", "id": "u22q3"}, {"type": "cloze", "prompt": "Completa con el GÉRONDIF de «courir» (dos palabras: en + participio presente).", "text": "Il est sorti ___ pour attraper le bus.", "answer": "en courant", "accepted": ["en courant"], "id": "u22q4"}, {"type": "cloze", "prompt": "Completa con el PARTICIPE PRÉSENT de «être» (una sola palabra; expresa la causa).", "text": "___ malade, il n''est pas venu travailler.", "answer": "Étant", "accepted": ["Etant", "Étant"], "id": "u22q5"}]'::jsonb)
