insert into public.study_theory (course_id, unit_order, cefr_level, title, summary, sections, examples, pitfalls, quiz)
values ('20000000-0000-0000-0000-000000000003', 24, 'B2', 'Voz pasiva avanzada y puesta de relieve', 'Cómo se forma la pasiva francesa y, sobre todo, cómo el francés la evita con on y se faire. Y cómo destacar un elemento con c''est… qui / c''est… que.', '[{"heading": "La pasiva: être + participio que concuerda", "body": "La pasiva se forma con être conjugado más el participio, que concuerda con el sujeto. El tiempo lo marca être, no el participio. El agente entra con par cuando hay una acción concreta, y con de con verbos de sentimiento o de descripción.", "bullets": ["être + participio: el participio concuerda con el sujeto.", "Acción concreta: par. Sentimiento o descripción: de.", "Casi solo los verbos con complemento directo admiten pasiva."]}, {"heading": "El francés prefiere evitar la pasiva", "body": "El francés recurre a la pasiva mucho menos que el español. Lo natural es on más verbo activo cuando el agente no importa, se faire más infinitivo cuando alguien sufre la acción, y la pasiva pronominal para lo habitual o general.", "bullets": ["On a construit ce pont: agente desconocido o irrelevante.", "Il s''est fait voler son vélo: alguien sufre la acción.", "Ce plat se mange froid: norma general, sin agente."]}, {"heading": "Poner de relieve: c''est… qui / c''est… que", "body": "Para destacar un elemento, el francés lo encierra en c''est… qui si ese elemento es el sujeto, y en c''est… que si es cualquier otro complemento. El español suele conseguir lo mismo solo con la entonación.", "bullets": ["C''est Marie qui l''a fait: sujeto destacado, qui.", "C''est ce livre que je veux: complemento, que.", "Ce que je veux, c''est partir: destaca la idea entera."]}]'::jsonb, '[{"fr": "Cette maison a été construite par mon grand-père.", "es": "Esta casa fue construida por mi abuelo.", "text": "Cette maison a été construite par mon grand-père.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/study/acdc2026-8e31-5ce3-b332-6a3edb093fff.mp3"}, {"fr": "On a annulé le concert à cause de la pluie.", "es": "Se canceló el concierto a causa de la lluvia.", "text": "On a annulé le concert à cause de la pluie.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/study/dbf6bdf3-d729-5918-8d7b-87f67df421f0.mp3"}, {"fr": "Il s''est fait voler son vélo devant la gare.", "es": "Le robaron la bici delante de la estación.", "text": "Il s''est fait voler son vélo devant la gare.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/study/24c1659b-55f0-5c34-b24d-84519af30991.mp3"}, {"fr": "Il est respecté de tous ses collègues.", "es": "Es respetado por todos sus colegas.", "text": "Il est respecté de tous ses collègues.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/study/683ca92f-e45c-5a4a-bfab-9dcfcc1e7c35.mp3"}]'::jsonb, '[{"title": "obéir à no se pone en pasiva", "body": "Solo los verbos con complemento directo admiten pasiva. Obéir lleva complemento indirecto (obéir à quelqu''un), así que en francés corriente no dirás «il est obéi»: dirás «On lui obéit»."}, {"title": "Tras «se faire»: «fait» invariable y luego INFINITIVO", "body": "Dos reglas: (a) «fait» no concuerda nunca — «elle s''est fait renvoyer», no «faite». (b) Lo que sigue va en INFINITIVO: «se faire voler», nunca «volé», aunque suenen igual."}, {"title": "qui o que no depende de persona o cosa", "body": "Elige por función: qui si el elemento destacado es el sujeto, que si es complemento. Y el verbo concuerda contigo: «C''est moi qui ai raison», no «a raison»."}]'::jsonb, '[{"type": "multiple_choice", "prompt": "«Estas casas fueron construidas por un arquitecto italiano.» ¿Cuál es la frase correcta en francés?", "options": ["Ces maisons ont été construites par un architecte italien.", "Ces maisons ont été construit par un architecte italien.", "Ces maisons ont été construits par un architecte italien."], "answer": "Ces maisons ont été construites par un architecte italien.", "id": "u24q1"}, {"type": "multiple_choice", "prompt": "«Se obedecieron las órdenes sin discutir.» ¿Cuál es la formulación normal en francés actual?", "options": ["On a obéi aux ordres sans discuter.", "Les ordres ont été obéis sans discuter.", "Les ordres se sont obéis sans discuter."], "answer": "On a obéi aux ordres sans discuter.", "id": "u24q2"}, {"type": "multiple_choice", "prompt": "«A él le robaron la bici.» ¿Cuál es la frase correcta?", "options": ["Il s''est fait voler son vélo.", "Il s''est fait volé son vélo.", "Il a été fait voler son vélo."], "answer": "Il s''est fait voler son vélo.", "id": "u24q3"}, {"type": "cloze", "prompt": "Destacamos el SUJETO: la que hizo el pastel fue Marie. Completa con qui o que.", "text": "C''est Marie ___ a fait ce gâteau.", "answer": "qui", "accepted": ["qui"], "id": "u24q4"}, {"type": "cloze", "prompt": "El francés evita la pasiva: «Este puente se construyó en 1990». Completa con el pronombre impersonal.", "text": "___ a construit ce pont en 1990.", "answer": "On", "accepted": ["on"], "id": "u24q5"}]'::jsonb)
